function renderRecommendedNextStep(workflow){const next=recommendedNextStep(workflow),button=$('recommendedNextAction');$('recommendedNextHeading').textContent=next.heading;$('recommendedNextText').textContent=next.text;button.textContent=next.label;button.onclick=next.action}
