 const saved=builderProgress?.item?.updated_at||builderProgress?.updated_at||builderProgress?.created_at;$('dashboardLastUpdated').textContent=saved?`Last saved ${new Date(saved).toLocaleString('en-GB')}`:'No Case Builder progress saved yet';
 const hearing=d.next_hearing||activeCase?.next_hearing,deadline=d.next_deadline||activeCase?.next_deadline;if(hearing){$('dashboardNextEvent').textContent=`Hearing: ${hearing}`;$('dashboardNextEventDetail').textContent=d.hearing_type||'Hearing type not yet recorded';}else if(deadline){$('dashboardNextEvent').textContent=`Deadline: ${deadline}`;$('dashboardNextEventDetail').textContent=d.deadline_description||'Deadline description not yet recorded';}else{$('dashboardNextEvent').textContent='No hearing or deadline recorded';$('dashboardNextEventDetail').textContent='Add the next court date when known.'}
 const evidenceCount=(d.materials||[]).length+(d.other_material?1:0);$('dashboardEvidenceCount').textContent=`${evidenceCount} categor${evidenceCount===1?'y':'ies'} recorded`;const foundationComplete=state.completed===totalSteps,propertyComplete=Boolean(propertyProgress?.item?.completed),bankComplete=Boolean(bankProgress?.item?.completed);$('dashboardFocus').textContent=!foundationComplete?sectionNames[state.next-1]:!propertyComplete?'Property and Housing':bankComplete?'Investigation Engine':'Bank Accounts and Transferred Funds';$('dashboardFocusDetail').textContent=!foundationComplete?'This is the next incomplete foundation section.':!propertyComplete?'Start the first evidence-led module.':bankComplete?'Review facts, evidence, gaps and issues before publishing them.':'Trace accounts, balances, transfers and missing statements.';$('dashboardNextText').textContent=!foundationComplete?`Continue from ${sectionNames[state.next-1]}.`:!propertyComplete?'Foundation complete. Begin Property and Housing.':bankComplete?'Review Bank Accounts and Funds or prepare for the next module.':'Property and Housing module complete. Continue with the financial trail.';$('continueInterview').textContent=!foundationComplete?'Continue Building My Case':'Investigate My Case';
