  findings.forEach(finding=>{const card=document.createElement('article');card.className='unsupported-fact-card';card.innerHTML=`<h3>${escapeHtml(finding.documentType)}</h3><p>${escapeHtml(finding.reason)}</p><button class="button secondary compact" type="button">Add to Review Centre as proposed</button>`;card.querySelector('button').onclick=()=>createMissingProposal(finding);list.appendChild(card)});
