 if(!visible.length&&!native.length){list.innerHTML='<div class="empty-intelligence"><strong>No evidence records match this view.</strong><p>No supporting evidence has been added yet, or the current filters exclude it.</p><button class="button primary" type="button">Add Supporting Evidence</button></div>';list.querySelector('button').onclick=()=>openEvidenceEditor();return}
